    def _resolve_dynamic_defaults(self, ctx: Context) -> None:
        """Resolve options whose ``default`` is a mapping of other
        option names to value lookups, now that every parameter for
        this context has been processed once.

        Only applies to options whose value still comes from
        :attr:`ParameterSource.DEFAULT`; explicit values (command line,
        environment variable, default map, ...) are left untouched.
        """
        params = self.get_params(ctx)

        for param in params:
            if (
                not isinstance(param, Option)
                or not param.is_dynamic_default
                or param.name is None
                or ctx.get_parameter_source(param.name) != ParameterSource.DEFAULT
            ):
                continue

            value = None

            for source_opt, value_map in param.default.items():
                source_param = next(
                    (
                        p
                        for p in params
                        if source_opt in p.opts or source_opt in p.secondary_opts
                    ),
                    None,
                )

                if source_param is None or source_param.name not in ctx.params:
                    continue

                source_key = str(ctx.params[source_param.name])

                if source_key in value_map:
                    value = value_map[source_key]

            if value is not None:
                ctx.params[param.name] = param.type_cast_value(ctx, value)

